<?php declare(strict_types=1); namespace App\Http\Controllers\Payroll; use App\Http\Controllers\Controller; use App\Http\Requests\Payroll\PayrollReasonRequest; use App\Models\Payroll\PayrollRun; use App\Services\Payroll\PayrollWorkflowService; use Illuminate\Http\RedirectResponse; use Illuminate\View\View; class PayrollApprovalController extends Controller{public function index():View{return view('payroll.approvals.index',['title'=>'Persetujuan Payroll','runs'=>PayrollRun::whereIn('status',['submitted','approved','revision'])->latest()->paginate(15)]);} public function submit(PayrollRun $run,PayrollWorkflowService $s):RedirectResponse{$s->submit($run,auth()->id());return back()->with('status','Payroll diajukan.');} public function approve(PayrollRun $run,PayrollWorkflowService $s):RedirectResponse{$s->approve($run,auth()->id());return back()->with('status','Payroll disetujui.');} public function reject(PayrollReasonRequest $r,PayrollRun $run,PayrollWorkflowService $s):RedirectResponse{$s->reject($run,$r->user()->id,$r->string('reason')->toString());return back()->with('status','Payroll diminta perbaikan.');} public function finalize(PayrollRun $run,PayrollWorkflowService $s):RedirectResponse{$s->finalize($run,auth()->id());return back()->with('status','Payroll difinalisasi dan nomor slip diterbitkan.');}}
